import json
with open('baseline-packages.json') as f: b = json.load(f)
with open('after-cpm-packages.json') as f: a = json.load(f)
def extract(data):
    result = {}
    for p in data['projects']:
        name = p['path'].split('/')[-2]
        for fw in p['frameworks']:
            for pkg in fw['topLevelPackages']:
                result.setdefault(name, []).append((pkg['id'], pkg['resolvedVersion']))
    return result
bp, ap = extract(b), extract(a)
if bp == ap:
    print('✅ Package versions are identical before and after conversion.')
else:
    print('⚠️ Differences detected:')
    for proj in sorted(set(list(bp.keys()) + list(ap.keys()))):
        if bp.get(proj) != ap.get(proj):
            print(f'  {proj}: before={bp.get(proj)} after={ap.get(proj)}')
"

